var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>여기는 E-1-5. 최초 급성침식파 발생 후 침식 수준 현상 유지 중.</color>","JPN":"<color=#ffd34c>こちら、E-1-5。最初の急性侵食波の発生後、侵食レベルは現状を維持中。</color>","ENG":"<color=#ffd34c>E-1-5 reporting, over. Corruption level stabilized after initial acute Corruption ray.</color>","TWN":"<color=#ffd34c>這裡是E-1-5，從第一個急性侵蝕波發生後，侵蝕現象一直在持續當中。</color>"},"stage":{"bg":"SKYLINE_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>도시구역 다수에서 동시다발적인 침식체 출몰을 확인.</color>","JPN":"<color=#ffd34c>多数の都市区域で同時多発的な侵食体の出没を確認。</color>","ENG":"<color=#ffd34c>C.O.s spotted in multiple locations around the city.</color>","TWN":"<color=#ffd34c>目前多個城市皆同時有侵蝕體出現，</color>"},"stage":{"bg":"SKYLINE_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>초동대응팀만으론 안전확보가 어렵다. 지원을 요청한다.</color>","JPN":"<color=#ffd34c>初動対応チームだけでは安全を確保することは難しい。支援を要請する。</color>","ENG":"<color=#ffd34c>We’re going to need more firepower. Requesting reinforcement, over.</color>","TWN":"<color=#ffd34c>光靠現有的人力難以確保安全，請求支援。</color>"},"stage":{"bg":"SKYLINE_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"여기는 HQ. 도시관리국 지침에 따라, 현 사태를 비상조치 레벨 3로 격상.","JPN":"こちら、HQ。都市管理局の指針により、当事態を非常措置レベル3に格上げ。","ENG":"This is HQ. Following the City Management guidelines, we hereby announce the current disaster’s severity as emergency level 3.","TWN":"這裡是HQ，根據城市管理局指示，升級為3級警戒。"},"stage":{"bg":"SKYLINE_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"관할 외 태스크포스들에게도 지원 요청을 승인받았습니다.","JPN":"管轄外のタスクフォースに送った支援要請も承認されています。","ENG":"We have obtained permission from all TASKFORCE out of our jurisdiction.","TWN":"轄區外的特遣勢力也已同意加入支援。"},"stage":{"bg":"SKYLINE_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"QUARANTINE_NPC_NULL_NULL","text":{"KOREA":"또 도시 한복판에서 급성 침식이라니. 이래선 내 집에서도 발 뻗고 못 자겠네.","JPN":"また都市の真ん中で急性侵食だなんて。これじゃあ自分の家でも安心して眠れないぞ。","ENG":"Another acute Corruption in the heart of the city? I guess I won’t even feel safe at my own home.","TWN":"市中心竟然又發生急性侵蝕，根本就沒時間可以休息嘛。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"QUARANTINE_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DEFENDER_NPC_NANAHARA2_NULL","text":{"KOREA":"한 달 사이에만 벌써 세 번째네요. 안전에 대한 시민들 여론도 최악이고요.","JPN":"今月すでに3回目ですからね。安全についての市民の世論も最悪ですし。","ENG":"It’s already the third time this month. Our reputation to the public hit rock bottom.","TWN":"這已經是這個月的第三次，現在都民怨沸騰了。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"QUARANTINE_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DEFENDER_NPC_NANAHARA2_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"QUARANTINE_NPC_NULL_NULL","text":{"KOREA":"어쩌겠어. 우린 신이 아니라 돈 받으며 최전선에서 궂은 일하는 사람들이라고.","JPN":"どうしろってんだ。俺たちは神様じゃなくて、お金もらって最前線できつい仕事をしてる普通の人なんだぜ。","ENG":"Well, there’s nothing we can do. We are just frontline workers, not god.","TWN":"能怎麼辦？我們又不是神，我們只是拿錢辦事而已，而且還是屎缺。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"QUARANTINE_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DEFENDER_NPC_NANAHARA2_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"QUARANTINE_NPC_NULL_NULL","text":{"KOREA":"음……? 방금 저쪽에서 무슨 소리 들리지 않았어?","JPN":"うん……？　さっきあそこから何か聞こえなかったか？","ENG":"Hmm...? Didn’t you hear something over there?","TWN":"嗯……？那邊好像有什麼聲音，你有聽到嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"QUARANTINE_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DEFENDER_NPC_NANAHARA2_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"DEFENDER_NPC_NANAHARA2_NULL","text":{"KOREA":"조심하세요. 그쪽 골목은 아직 안전한지 모르는……","JPN":"気をつけてくださいよ。そっちの裏道はまだ安全かどうかわからな……","ENG":"Be careful. We haven’t checked the alleyway over–","TWN":"小心點，那條巷子不知道安不安全……"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"DEFENDER_NPC_NANAHARA2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"우와앗!!!","JPN":"うわっ！！！","ENG":"Whoa!!!","TWN":"啊啊啊！！！"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"DEFENDER_NPC_NANAHARA2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DEFENDER_NPC_NANAHARA2_NULL","text":{"KOREA":"이런!","JPN":"しまった！","ENG":"Oh, no!","TWN":"該死！"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"DEFENDER_NPC_NANAHARA2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DEFENDER_NPC_NANAHARA2_NULL","text":{"KOREA":"침식체입니까?!","JPN":"侵食体ですか！？","ENG":"Is it a C.O.?!","TWN":"是侵蝕體嗎？！"},"stage":{"bg":"CITY_CENTER2","slots":{"L":{"char_id":"QUARANTINE_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DEFENDER_NPC_NANAHARA2_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"QUARANTINE_NPC_NULL_NULL","text":{"KOREA":"그…… 그렇긴 한데…….","JPN":"そ……そうなんだが……","ENG":"I... I think so...?","TWN":"是……沒錯……"},"stage":{"bg":"CITY_CENTER2","slots":{"L":{"char_id":"QUARANTINE_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DEFENDER_NPC_NANAHARA2_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"QUARANTINE_NPC_NULL_NULL","text":{"KOREA":"누가 이미 다녀간 것 같은데?","JPN":"すでに誰かが来てたみたいだぞ？","ENG":"But it looks like someone’s already taken care of them.","TWN":"但好像有人來過咧？"},"stage":{"bg":"CITY_CENTER2","slots":{"L":{"char_id":"QUARANTINE_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DEFENDER_NPC_NANAHARA2_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"DEFENDER_NPC_NANAHARA2_NULL","text":{"KOREA":"이럴 수가. 누가 이렇게 많은 침식체들을 전부 해치운 거죠?","JPN":"そんな。誰がこの数の侵食体を全部片付けたんでしょうか？","ENG":"Unbelievable. How could anyone take down this many C.O.s all at once?","TWN":"怎麼可能，誰有辦法處理掉這麼多侵蝕體？"},"stage":{"bg":"CITY_CENTER2","slots":{"L":{"char_id":"QUARANTINE_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DEFENDER_NPC_NANAHARA2_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};